-- StatusOS v2.0.0 Database-First Artist OS\n-- Run once in Supabase SQL Editor before using Artist OS across devices.\ncreate extension if not exists pgcrypto;\ncreate table if not exists public.artists (id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,name text not null,contact text,email text,genre text,status text not null default 'New Lead',follow_up date,last_contact date,notes text,version integer not null default 1,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz);\ncreate table if not exists public.artist_activities (id uuid primary key default gen_random_uuid(),artist_id uuid not null references public.artists(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,type text not null,title text not null,details text,activity_date date not null default current_date,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),deleted_at timestamptz);\ncreate table if not exists public.artist_versions (id bigint generated always as identity primary key,artist_id uuid not null,user_id uuid not null,version integer not null,snapshot jsonb not null,created_at timestamptz not null default now());\ncreate index if not exists artists_user_updated_idx on public.artists(user_id,updated_at desc);\ncreate index if not exists artist_activities_artist_date_idx on public.artist_activities(artist_id,activity_date desc);\nalter table public.artists enable row level security;alter table public.artist_activities enable row level security;alter table public.artist_versions enable row level security;\ndrop policy if exists artists_own_all on public.artists;create policy artists_own_all on public.artists for all using(auth.uid()=user_id) with check(auth.uid()=user_id);\ndrop policy if exists artist_activities_own_all on public.artist_activities;create policy artist_activities_own_all on public.artist_activities for all using(auth.uid()=user_id) with check(auth.uid()=user_id);\ndrop policy if exists artist_versions_own_select on public.artist_versions;create policy artist_versions_own_select on public.artist_versions for select using(auth.uid()=user_id);\ndrop policy if exists artist_versions_own_insert on public.artist_versions;create policy artist_versions_own_insert on public.artist_versions for insert with check(auth.uid()=user_id);\ncreate or replace function public.statusos_capture_artist_version() returns trigger language plpgsql security definer set search_path=public as $$ begin if tg_op='UPDATE' then insert into public.artist_versions(artist_id,user_id,version,snapshot) values(old.id,old.user_id,old.version,to_jsonb(old)); end if; new.updated_at=now(); new.version=greatest(coalesce(old.version,0)+1,coalesce(new.version,1)); return new; end $$;\ndrop trigger if exists statusos_artist_version_trigger on public.artists;create trigger statusos_artist_version_trigger before update on public.artists for each row execute function public.statusos_capture_artist_version();\ndo $$ begin begin alter publication supabase_realtime add table public.artists; exception when duplicate_object then null; end; begin alter publication supabase_realtime add table public.artist_activities; exception when duplicate_object then null; end; end $$;\n